@Slf4j
public abstract class AbstractBerekenSocialeBijdragen extends AbstractRekenCommand {

    public static final Set<MoneyKey> VR_BR_RSZ_KEYS = ImmutableSet.of(
            RekenBasisRszKey.BASIS_RSZ_KEY,
            RekenRszKey.BIJDRAGE_RSZ_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_MEER_DAN_10WERKNEMERS_KEY);

    public static final int AANTAL_SOLIDARITEIDSBIJDRAGE_GRENZEN = 4;
    public static final int AANTAL_SOLIDARITEITSBIJDRAGE_INHOUDINGEN = 5;
    public static final int PRECISIE = 2;
    public static final int HONDERD = 100;

    protected static final int JA = Janeen.JA.getCode();
    protected static final int NEEN = Janeen.NEEN.getCode();
    private static final Set<MoneyKey> BIJDRAGEN = ImmutableSet.of(
            RekenRszKey.BIJDRAGE_RSZ_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY,
            RekenRszKey.BIJDRAGE_OVERUREN_GECO_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_OVERUREN_GECO_KEY,
            RekenRszKey.BIJDRAGE_TAO_KEY,
            RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY,
            RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY,
            RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_VOERTUIG_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TERUGBETALING_VERKEERSBOETES_KEY,
            RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_MANDATARIS_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_ERKENTELIJKHEIDSPREMIE_KEY,
            RekenRszKey.BIJDRAGE_PENSIOEN_MANDATARIS_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_MANDATARIS_KEY,
            RekenPatronaalRszKey.VERMINDERING_PATRONALE_BIJDRAGE_RSZ_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_GSD_KEY,
            RekenRszKey.BIJDRAGE_BRUG_PENSIOEN_KEY,
            RekenRszKey.BIJDRAGE_MOBILITEITSBUDGET_KEY,
            RekenPatronaalRszKey.PATRONALE_BIJDRAGE_CORONAPREMIE_KEY);

    private static final LocalDate START_SOLIDARITEITSBIJDRAGE_PENSIOEN = new LocalDate(1995, 1, 1);

    private static final int GRENS_JAAR_ERKENTELIJKHEIDSPREMIE = 1988;
    private static final BigDecimal VIJFENZESTIG = BigDecimal.valueOf(65);
    private static final BigDecimal TWINTIG = BigDecimal.valueOf(20);
    private static final LocalDate DATUM_NIEUWE_REGEL_VERPLICHT_RIZIV = new LocalDate(2025, 1, 1);

    protected final ConstantManager constantManager;
    protected final BijdragePercentagesFactory bijdragePercentagesFactory;
    private final ControleRszKwartaalGrensVrijwilligeBrandweer controleVrijeBrandweer;

    protected AbstractBerekenSocialeBijdragen(
            ConstantManager constantManager, NlpGlobalService globalService, ControleRszKwartaalGrensVrijwilligeBrandweer controleVrijeBrandweer) {
        this.constantManager = constantManager;
        this.bijdragePercentagesFactory = new BijdragePercentagesFactoryImp(constantManager, globalService);
        this.controleVrijeBrandweer = controleVrijeBrandweer;
    }

    static Money berekenBijdrage(
            MoneyKey basisKey, MoneyKey bijdrageKey, Collection<LoonElement> loonElementen, SleutelGegevens aggregaat,
            BijdragePercentages bijdragePercentages, LocalDate zoekDatum) {
        Money basisSocialeBijdrage = RekenTools.getSomProperty(basisKey, loonElementen);

        Money bijdrage = Money.ZERO;
        log.debug("{} {}={}", aggregaat, basisKey, basisSocialeBijdrage);
        if (basisSocialeBijdrage.signum() != 0) {
            BigDecimal percentageBijdrage = bijdragePercentages.bepaal(bijdrageKey, aggregaat, zoekDatum);
            bijdrage = basisSocialeBijdrage.multiply(percentageBijdrage);
            log.debug("percentage={},{}={}", percentageBijdrage, bijdrageKey, bijdrage);
            PercentageBasisVormer.vormBedragAlsPercentageBasisAdd(bijdrageKey, basisKey, percentageBijdrage, loonElementen);
            log.debug("{};basisKey \"{}\":{};bijdrageKey \"{}\":{}", LogTools.toSimpleLog(aggregaat), basisKey, basisSocialeBijdrage, bijdrageKey, bijdrage);
            if (bijdrageKey == RekenPatronaalRszKey.PATRONALE_BASISBIJDRAGE_RSZ_ZIV_KEY
                    || bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJZONDERE_BIJDRAGE_ASBESTFONDS
                    || bijdrageKey == RekenPatronaalRszKey.PATRONALE_BIJZONDERE_BIJDRAGE_ARBEIDSONGEVALLEN
                    || bijdrageKey == RekenPatronaalPriveRszKey.PATRONALE_BIJDRAGE_VAKREG_PRIVESECTOR_KEY) {
                PercentageBasisVormer.vormBedragAlsPercentageBasisAdd(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY,
                        basisKey, percentageBijdrage, loonElementen);
            }
        }
        return bijdrage;
    }

    private static void hersommeerVrBrRsz(RekenContext mainContext) {
        Persoon persoon = mainContext.getUnchecked(RekenChainKey.PERSOON_KEY);
        LoonElementManager manager = mainContext.getLoonElementManager();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
            for (MoneyKey opdrachtBedragKey : VR_BR_RSZ_KEYS) {
                opdrachtContext.put(opdrachtBedragKey, RekenTools.getSomProperty(opdrachtBedragKey, loonElementen));
            }
        }
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getRekenTijd();
        LoonElementManager manager = mainContext.getLoonElementManager();
        RegulManager regulManager = mainContext.getRegulManager();
        Persoon persoon = mainContext.getUnchecked(RekenChainKey.PERSOON_KEY);
        Set<Opdracht> opdrachten = persoon.getOpdrachten();
        for (Opdracht opdracht : opdrachten) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);

            berekenSocialeBijdragenHoedanigheid(opdracht, opdrachtContext);
            berekenSocialeBijdrageVoertuig(opdrachtContext, opdracht, regulManager);
            controleerRegulBasisRszNegatief(opdracht, manager, regulManager);
        }

        berekenVakbondspremie(mainContext, rekenTijd, opdrachten);

        PersoonsDataManager dataManager = mainContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        Persoon persoonKwartaalSimpel = dataManager.getPersoonKwartaalSimpel();

        if (persoonKwartaalSimpel != null && RekenTools.heeftOpdrachtVrijwilligeBrandweer(persoonKwartaalSimpel)) {
            List<RekenHoofd> kwartaalResultaten = dataManager.getKwartaalRekenResultaten();
            List<Opdracht> opdrachtKwartalen = dataManager.getKwartaalOpdrachten();
            controleVrijeBrandweer.controleer(persoonKwartaalSimpel, rekenTijd, manager, kwartaalResultaten, opdrachtKwartalen, regulManager);
            hersommeerVrBrRsz(mainContext);
        }

        return CONTINUE_PROCESSING;
    }

    void berekenVakbondspremie(RekenContext mainContext, RekenTijd rekenTijd, Set<Opdracht> opdrachten) {
        Constant vakbondspremieRekenenConstante = constantManager.getActualConstant(Konstanten.KST_VAKBONDSPREMIE_REKENEN, rekenTijd);
        boolean isVakbondspremieRekenen = vakbondspremieRekenenConstante.getJaneen();
        if (isVakbondspremieRekenen) {
            vakbondspremieRekenen(mainContext, rekenTijd, opdrachten);
        }
    }

    void vakbondspremieRekenen(RekenContext mainContext, RekenTijd rekenTijd, Set<Opdracht> opdrachten) {
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        Vakbondspremie vakbondspremie =
                Vakbondspremie.create(mainContext, constantManager, persoonsDataManager, mainContext.getLoonElementManager(), rekenTijd, opdrachten);
        vakbondspremie.bereken();
    }

    protected void berekenSocialeBijdragenHoedanigheid(Opdracht opdracht, RekenContext opdrachtContext) {
        switch (opdracht.getHoedanigheid()) {
            case MANDATARISSEN:
                berekenSocialeBijdragenMandataris(opdrachtContext, opdracht);
                break;
            case WERKNEMERS_GEPENSIOENEERD:
            case MANDATARISSEN_GEPENSIOENEERD:
                berekenSocialeBijdragenGepensioeneerd(opdrachtContext, opdracht);
                berekenSolidariteitsBijdragePensioen(opdrachtContext, opdracht);
                break;
            case RAADSLEDEN:
            case COMMISSIELEDEN:
            case JURYLEDEN:
            case BEZOLDIGDEN_ZONDER_OVEREENKOMST:
                //niet onderworpen
                break;
            case ERKENTELIJKHEIDSPREMIE:
            case VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE:
                berekenSocialeBijdragenErkentelijkheidsPremie(opdrachtContext, opdracht);
                berekenSolidariteitsBijdragePensioen(opdrachtContext, opdracht);
                break;
            case MONITOREN:
                berekenSocialeBijdrageMonitoren(opdrachtContext, opdracht);
                break;
            default:
                berekenSocialeBijdragenRszppoPlichtig(opdrachtContext, opdracht);
                break;
        }
    }

    public abstract void berekenSocialeBijdrageVoertuig(RekenContext opdrachtContext, Opdracht opdracht, RegulManager regulManager);

    public abstract void berekenSocialeBijdragenRszppoPlichtig(RekenContext opdrachtContext, Opdracht opdracht);

    public abstract void berekenSocialeBijdragenMandataris(RekenContext opdrachtContext, Opdracht opdracht);

    public abstract void berekenSocialeBijdrageMonitoren(RekenContext opdrachtContext, Opdracht opdracht);

    protected void berekenBijdrage(RekenContext context, MoneyKey basisKey, MoneyKey bijdrageKey, List<SleutelGegevens> aggregaten) {
        boolean gegevensVorigKwartaal = context.getBoolean(RekenChainKey.RSZ_VORIG_KWARTAAL_KEY);
        if (gegevensVorigKwartaal) {
            LocalDate selectieVorigKwartaal = context.getUnchecked(RekenChainKey.SELECTIE_DATUM_VORIG_KWARTAAL_KEY);
            Opper opperVorigKwartaal = context.getUnchecked(RekenChainKey.OPPER_VORIG_KWARTAAL_KEY);
            berekenBijdrageVorigKwartaal(context, basisKey, bijdrageKey, selectieVorigKwartaal, opperVorigKwartaal);
        } else {
            berekenBijdrageNormaal(context, basisKey, bijdrageKey, aggregaten);
        }
    }

    private void berekenBijdrageNormaal(RekenContext context, MoneyKey basisKey, MoneyKey bijdrageKey, List<SleutelGegevens> aggregaten) {
        log.debug("berekenBijdrage(context,\"{}\",\"{}\",agregaten)", basisKey, bijdrageKey);
        RekenTijd rekenTijd = context.getRekenTijd();
        LoonElementManager manager = context.getLoonElementManager();
        RegulManager regulManager = context.getRegulManager();
        BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
        Money bijdrageTotaal = Money.ZERO;
        for (SleutelGegevens aggregaat : aggregaten) {
            Collection<LoonElement> opperElementen = aggregaat.getOpperElementen(manager);
            LocalDate zoekDatum = TimeTools.getZoekDatum(aggregaat, rekenTijd.rekenPeriode);
            Money bijdrage = berekenBijdrage(basisKey, bijdrageKey, opperElementen, aggregaat, bijdragePercentages, zoekDatum);
            bijdrageTotaal = bijdrageTotaal.add(bijdrage);

            log.trace("aggregaatElementen:{}", opperElementen);
        }
        context.put(bijdrageKey, bijdrageTotaal.round(PRECISIE));
    }

    protected void berekenBijdrage(RekenContext context, MoneyKey basisKey, BigDecimal percentageBijdrage, MoneyKey bijdrageKey, Opdracht opdracht) {
        LoonElementManager manager = context.getLoonElementManager();
        Money bijdrage = Money.ZERO;
        Money basisSocialeBijdrage = context.getMoney(basisKey);
        if (basisSocialeBijdrage != null && basisSocialeBijdrage.signum() != 0) {
            bijdrage = basisSocialeBijdrage.multiply(percentageBijdrage).round(PRECISIE);
            for (Opper opper : opdracht.getOpperSlices()) {
                Collection<LoonElement> loonElementen = manager.getOpperElementen(opper);
                PercentageBasisVormer.vormBedragAlsPercentageBasisPut(bijdrageKey, basisKey, percentageBijdrage, loonElementen);
            }
        }
        context.put(bijdrageKey, bijdrage);
    }

    private void berekenBijdrageVorigKwartaal(
            RekenContext context, MoneyKey basisKey, MoneyKey bijdrageKey, LocalDate zoekDatumVorigKwartaal, Opper opperVorigKwartaal) {
        log.debug("berekenBijdrageVorigKwartaal(context,\"{}\",\"{}\",{},opperVorigKwartaal)", basisKey, bijdrageKey, zoekDatumVorigKwartaal);
        RekenTijd rekenTijd = context.getRekenTijd();
        LoonElementManager manager = context.getLoonElementManager();
        RegulManager regulManager = context.getRegulManager();
        BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
        SleutelGegevens aggregaat = new SleutelGegevensSingleOpper(opperVorigKwartaal);

        Collection<LoonElement> opdrachtsElementen = manager.getOpdrachtsElementen(aggregaat.getOpdracht());
        Money bijdrageTotaal = berekenBijdrage(basisKey, bijdrageKey, opdrachtsElementen, aggregaat, bijdragePercentages, zoekDatumVorigKwartaal);

        log.trace("opdrachttElementen:{}", opdrachtsElementen);
        context.put(bijdrageKey, bijdrageTotaal.round(PRECISIE));
    }

    protected void berekenSocialeBijdragenGepensioeneerd(RekenContext opdrachtContext, Opdracht opdracht) {
        verdeelBasisRszGepensioeneerd(opdrachtContext, opdracht);
        sommeerBasissen(opdrachtContext, opdracht, RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY);
        bepaalBijdragenGepensioeneerd(opdrachtContext, opdracht, false);
        checkBasisEnBijdragePensioen(opdrachtContext, opdracht);
    }

    protected void checkBasisEnBijdragePensioen(RekenContext opdrachtContext, Opdracht opdracht) {
        LoonElementManager manager = opdrachtContext.getLoonElementManager();
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        Money bijdragePensioen = RekenTools.getSomProperty(RekenRszKey.BIJDRAGE_ZIV_GEPENSIONEERD_KEY, loonElementen);
        Money inhoudingBegrafenis = RekenTools.getSomProperty(RekenRszKey.BIJDRAGE_GEPENSIOENEERD_BEGRAFENIS_KEY, loonElementen);
        if (bijdragePensioen.signum() == 0 && inhoudingBegrafenis.signum() == 0) {
            opdrachtContext.put(RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY, Money.ZERO);
            for (LoonElement element : loonElementen) {
                element.putProperty(RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY, Money.ZERO);
            }
        }
    }

    public void verdeelBasisRszGepensioeneerd(RekenContext opdrachtContext, Opdracht opdracht) {
        LoonElementManager manager = opdrachtContext.getLoonElementManager();
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (LoonElement loonElement : loonElementen) {
            verdeelBasisRszGepensioeneerd(loonElement);
        }
    }

    public void verdeelBasisRszGepensioeneerd(LoonElement loonElement) {
        boolean onderworpen = !loonElement.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.ZONDER_BAS_SI_KEY);
        if (onderworpen) {
            Money bedrag = loonElement.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY);
            loonElement.putProperty(RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY, bedrag);
        }
    }

    private void bepaalBijdragenGepensioeneerd(RekenContext opdrachtContext, Opdracht opdracht, boolean erkentelijkheidsPremie) {
        RekenTijd rekenTijd = opdrachtContext.getRekenTijd();

        Money basisPensioen = opdrachtContext.getMoney(RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY);

        Opper opper = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
        PensioenEnMandataris pensioen = opper.getPensioenEnMandataris();

        Money inhoudingBegrafenis = Money.ZERO;
        if (!erkentelijkheidsPremie) {
            inhoudingBegrafenis = berekenBijdrageGepensioeneerdBegrafenis(basisPensioen, pensioen, rekenTijd);
            opdrachtContext.put(RekenRszKey.BIJDRAGE_GEPENSIOENEERD_BEGRAFENIS_KEY, inhoudingBegrafenis);
        }

        Money bijdragePensioen = Money.ZERO;
        switch (pensioen.getPensioenInhoudingZiv()) {
            case BAREMA:
                bijdragePensioen = berekenBijdrageGepensioeneerdBarema(basisPensioen, pensioen, erkentelijkheidsPremie, rekenTijd);
                break;
            case VERPLICHT_RIZIV:
                bijdragePensioen = berekenBijdrageGepensioeneerdVerplichtRiziv(basisPensioen, pensioen, rekenTijd);
                break;
            case GEEN_RIZIV:
                //doe niets
                break;
            default:
                RegulManager regulManager = opdrachtContext.getRegulManager();
                regulManager.doRegulException(opdracht, Regulkode.NIET_GEPROGRAMMEERD);
                break;
        }
        opdrachtContext.put(RekenRszKey.BIJDRAGE_ZIV_GEPENSIONEERD_KEY, bijdragePensioen);

        LoonElementManager manager = opdrachtContext.getLoonElementManager();
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        if (bijdragePensioen.signum() != 0 || inhoudingBegrafenis.signum() != 0) {
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(
                    RekenRszKey.BIJDRAGE_ZIV_GEPENSIONEERD_KEY, bijdragePensioen, RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY, basisPensioen, loonElementen);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(
                    RekenRszKey.BIJDRAGE_GEPENSIOENEERD_BEGRAFENIS_KEY, inhoudingBegrafenis, RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY, basisPensioen, loonElementen);
        }
    }

    private Money berekenBijdrageGepensioeneerdBegrafenis(Money basisPensioen, PensioenEnMandataris pensioen, RekenTijd rekenTijd) {
        Money inhoudingBegrafenis = Money.ZERO;
        if (pensioen.getPensioenInhoudingBegrafenisKost() == JA) {
            BigDecimal percentageInhoudingBegrafenis =
                    constantManager.getActualConstant(Konstanten.KST_PCT_INH_BEGRAF_GEPENS, rekenTijd).getProcentFactor();
            inhoudingBegrafenis = basisPensioen.multiply(percentageInhoudingBegrafenis.movePointLeft(2)).round(PRECISIE);
        }
        return inhoudingBegrafenis;
    }

    private Money berekenBijdrageGepensioeneerdBarema(Money basisPensioen, PensioenEnMandataris pensioen, boolean jaarGrens, RekenTijd rekenTijd) {
        boolean pensioenGezinsLast = pensioen.getPensioenGezinsLast() == JA;
        BigDecimal percentageInhouding = constantManager.getActualConstant(Konstanten.KST_PCT_ZIV_INH_GEPENS, rekenTijd).getProcentFactor();
        Money bijdragePensioen = basisPensioen.multiply(percentageInhouding).round(PRECISIE);
        Konstanten grensConstant = pensioenGezinsLast ? Konstanten.KST_GRENS2_ZIV_GEPENS : Konstanten.KST_GRENS1_ZIV_GEPENS;
        Money grens = constantManager.getActualConstant(grensConstant, rekenTijd).getMoney();
        if (jaarGrens) {
            grens = grens.multiply(RekenTools.TWELVE);
        }

        bijdragePensioen = getBijdragePensioenGrens(basisPensioen, bijdragePensioen, grens);
        return bijdragePensioen;
    }

    private Money berekenBijdrageGepensioeneerdVerplichtRiziv(Money basisPensioen, PensioenEnMandataris pensioen, RekenTijd rekenTijd) {
        BigDecimal percentageInhouding;
        if (rekenTijd.getBeginDatum().isBefore(DATUM_NIEUWE_REGEL_VERPLICHT_RIZIV)) {
            percentageInhouding = constantManager.getActualConstant(Konstanten.KST_PCT_ZIV_INH_GEPENS, rekenTijd).getProcentFactor();
        } else {
            percentageInhouding = Optional.ofNullable(pensioen.getPensioenInhoudingZivPercentage())
                    .map(ziv -> ziv.divide(new BigDecimal("100"), 4, RoundingMode.HALF_UP))
                    .orElse(BigDecimal.ZERO);
        }
        return basisPensioen.multiply(percentageInhouding).round(PRECISIE);
    }

    private Money getBijdragePensioenGrens(Money basisPensioen, Money bijdragePensioen, Money grens) {
        if (basisPensioen.subtract(bijdragePensioen).compareTo(grens) > 0) {
            return bijdragePensioen;
        } else if (basisPensioen.compareTo(grens) > 0) {
            return basisPensioen.subtract(grens);
        } else {
            return Money.ZERO;
        }
    }

    protected void berekenSolidariteitsBijdragePensioen(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getRekenTijd();
        if (rekenTijd.beginDatum.isAfter(START_SOLIDARITEITSBIJDRAGE_PENSIOEN)) {
            verdeelBasisRszSolidariteitsBijdragePensioen(opdrachtContext, opdracht);
            sommeerBasissen(opdrachtContext, opdracht, RekenBasisRszKey.BASIS_SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY);
            bepaalBijdragenSolidariteitsBijdragePensioen(opdrachtContext, opdracht);
        }
    }

    public void verdeelBasisRszSolidariteitsBijdragePensioen(RekenContext opdrachtContext, Opdracht opdracht) {
        LoonElementManager manager = opdrachtContext.getLoonElementManager();
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (LoonElement element : loonElementen) {
            boolean komtInAanmerking = !element.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.GEEN_SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY);
            if (komtInAanmerking) {
                Money basisBijdrage = element.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY);
                element.putProperty(RekenBasisRszKey.BASIS_SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY, basisBijdrage);
            }
        }
    }

    public void verdeelBasisRszSolidariteitsBijdragePensioen(LoonElement element) {
        boolean komtInAanmerking = !element.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.GEEN_SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY);
        if (komtInAanmerking) {
            Money basisBijdrage = element.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY);
            element.putProperty(RekenBasisRszKey.BASIS_SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY, basisBijdrage);
        }
    }

    private void bepaalBijdragenSolidariteitsBijdragePensioen(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getRekenTijd();
        Money basisBijdrage = opdrachtContext.getMoney(RekenBasisRszKey.BASIS_SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY);
        if (basisBijdrage.signum() != 0) {
            Money bijdrage = Money.ZERO;
            Opper opper = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
            PensioenEnMandataris pensioen = opper.getPensioenEnMandataris();
            RegulManager regulManager = opdrachtContext.getRegulManager();
            switch (getSolBijdrageType(opper, regulManager)) {
                case BAREMA -> bijdrage = rekenSolidariteitsBijdrageBarema(basisBijdrage, pensioen, rekenTijd);
                case BEDRAG_INHOUDING -> bijdrage = pensioen.getPensioenInhoudingSolidariteitsBijdrage();
                case PERCENTAGE -> bijdrage = basisBijdrage.multiply(pensioen.getPensioenSolidariteitsBijdragePercentage()).divide(HONDERD).round(PRECISIE);
                default -> regulManager.doRegulException(opdracht, Regulkode.ONGELDIGE_KODE_SOLBIJDRAGE);
            }
            opdrachtContext.put(RekenRszKey.SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY, bijdrage);

            LoonElementManager manager = opdrachtContext.getLoonElementManager();
            Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(RekenRszKey.SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY, bijdrage,
                    RekenBasisRszKey.BASIS_SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY,
                    basisBijdrage, loonElementen);
        }
    }

    private SolBijdrage getSolBijdrageType(Opper opper, RegulManager regulManager) {
        SolBijdrage bijdrageType = SolBijdrage.BAREMA;
        try {
            PensioenEnMandataris pensioen = opper.getPensioenEnMandataris();
            bijdrageType = pensioen.getPensioenSolidariteitsBijdrageType();
        } catch (Exception exception) {
            regulManager.doRegulException(opper.getOpdracht(), Regulkode.ONGELDIGE_KODE_SOLBIJDRAGE);
        }
        return bijdrageType;
    }

    protected Money rekenSolidariteitsBijdrageBarema(Money maandInkomen, PensioenEnMandataris pensioen, RekenTijd rekenTijd) {

        Money[] grens = getGrens(pensioen, rekenTijd);

        BigDecimal[] percentage = getPercentage(rekenTijd);

        int grensNr = 0;
        while (grensNr < AANTAL_SOLIDARITEIDSBIJDRAGE_GRENZEN && maandInkomen.compareTo(grens[grensNr]) >= 0) {
            grensNr++;
        }
        Money inhouding = maandInkomen.multiply(percentage[grensNr]);
        if (grensNr > 0) {
            Money inhouding2 = grens[grensNr - 1].multiply(percentage[grensNr - 1]).add(maandInkomen.subtract(grens[grensNr - 1]).divide(2));
            inhouding = inhouding.min(inhouding2);
        }

        return inhouding.round(PRECISIE);
    }

    protected Money[] getGrens(PensioenEnMandataris pensioen, RekenTijd rekenTijd) {
        if (pensioen.getPensioenGezinsLast() == NEEN) {
            return getGrens(rekenTijd, new Konstanten[]{Konstanten.SOLBD_GRA1, Konstanten.SOLBD_GRA2, Konstanten.SOLBD_GRA3, Konstanten.SOLBD_GRA4});
        } else {
            return getGrens(rekenTijd, new Konstanten[]{Konstanten.SOLBD_GRB1, Konstanten.SOLBD_GRB2, Konstanten.SOLBD_GRB3, Konstanten.SOLBD_GRB4});
        }
    }

    protected Money[] getGrens(RekenTijd rekenTijd, Konstanten[] konstantes) {
        Money[] grens = new Money[AANTAL_SOLIDARITEIDSBIJDRAGE_GRENZEN];
        for (int i = 0; i < konstantes.length; i++) {
            grens[i] = constantManager.getActualConstant(konstantes[i], rekenTijd).getMoney();
        }
        return grens;
    }

    protected BigDecimal[] getPercentage(RekenTijd rekenTijd) {
        BigDecimal[] percentage = new BigDecimal[AANTAL_SOLIDARITEITSBIJDRAGE_INHOUDINGEN];
        Konstanten[] konstanten = new Konstanten[]{Konstanten.SOLBD_INH1, Konstanten.SOLBD_INH2, Konstanten.SOLBD_INH3, Konstanten.SOLBD_INH4, Konstanten.SOLBD_INH5};
        for (int i = 0; i < konstanten.length; i++) {
            percentage[i] = constantManager.getActualConstant(konstanten[i], rekenTijd).getProcentFactor();
        }
        return percentage;
    }

    public void berekenSocialeBijdragenErkentelijkheidsPremie(RekenContext opdrachtContext, Opdracht opdracht) {
        verdeelBasisRszGepensioeneerd(opdrachtContext, opdracht);
        sommeerBasissen(opdrachtContext, opdracht, RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY);
        bepaalBijdragenGepensioeneerd(opdrachtContext, opdracht, true);
        bepaalPatronaleBijdrageErkentelijkheidsPremie(opdrachtContext, opdracht);
        checkBasisEnBijdragePensioen(opdrachtContext, opdracht);
        sommeerBasissen(opdrachtContext, opdracht, RekenBasisRszKey.BASIS_BUITENWETTELIJK_PENSIOEN_KEY);
    }

    public void bepaalPatronaleBijdrageErkentelijkheidsPremie(RekenContext opdrachtContext, Opdracht opdracht) {
        Money basisTotaal = opdrachtContext.getMoney(RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY);
        LocalDate geboorteDatum = opdracht.getPersoon().getGeboorteDatum();
        BigDecimal leeftijdOpGrensdatum = BigDecimal.valueOf(GRENS_JAAR_ERKENTELIJKHEIDSPREMIE - (long) geboorteDatum.getYear()).max(TWINTIG);
        if (basisTotaal.signum() != 0 && leeftijdOpGrensdatum.compareTo(VIJFENZESTIG) <= 0) {
            RekenTijd rekenTijd = opdrachtContext.getRekenTijd();
            RegulManager regulManager = opdrachtContext.getRegulManager();
            BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
            Opper opper = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
            SleutelGegevens aggregaat = new SleutelGegevensSingleOpper(opper);
            LocalDate zoekDatum = TimeTools.getZoekDatum(aggregaat, rekenTijd.rekenPeriode);
            BigDecimal percentage = bijdragePercentages.bepaal(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_ERKENTELIJKHEIDSPREMIE_KEY, aggregaat, zoekDatum);

            Money basisErkentelijkheidsPremie =
                    basisTotaal.multiply(VIJFENZESTIG.subtract(leeftijdOpGrensdatum)).divide(VIJFENZESTIG.subtract(TWINTIG));
            Money bijdrageTotaal = basisErkentelijkheidsPremie.multiply(percentage);

            opdrachtContext.put(RekenPatronaalRszKey.PATRONALE_BIJDRAGE_ERKENTELIJKHEIDSPREMIE_KEY, bijdrageTotaal);

            LoonElementManager manager = opdrachtContext.getLoonElementManager();
            Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(
                    RekenPatronaalRszKey.PATRONALE_BIJDRAGE_ERKENTELIJKHEIDSPREMIE_KEY, bijdrageTotaal,
                    RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY, basisTotaal, loonElementen);
            if (RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.DMFAPPL) {
                BedragVerdelerFactory.verdeelBedragVolgensBasisPut(RekenBasisRszKey.BASIS_BUITENWETTELIJK_PENSIOEN_KEY, basisErkentelijkheidsPremie,
                        RekenBasisRszKey.BASIS_ZIV_GEPENSIONEERD_KEY, basisTotaal, loonElementen);
            }
        }

    }

    protected boolean heeftPatronaleBijdrageMeerDan10Werknemers(Werkgever werkgever, RekenTijd rekenTijd) {
        boolean heeftBijdrage = true;
        Integer startKode = constantManager.getActualConstant(Konstanten.KST_START_10_WN, rekenTijd).getInteger();
        Constant principe = constantManager.getActualConstantSafe(startKode + werkgever.getWerkgeverNr(), rekenTijd);
        if (principe != null) {
            heeftBijdrage = principe.getBoolean();
        }
        return heeftBijdrage;
    }

