    protected void activeerRegulVoorKwartaalOpdrachten(
            RekenTijd rekenTijd, List<Opdracht> opdrachtenKwartaal, RegulManager regulManager, Regulkode regulKode, boolean currentMonth) {
        Quarter kwartaal = new Quarter(rekenTijd.beginDatum);
        List<LocalDate> kwartaalDatums = ImmutableList.of(kwartaal.getStart(), kwartaal.getStart().plusMonths(1), kwartaal.getStart().plusMonths(2));
        for (Opdracht opdracht : opdrachtenKwartaal) {
            LocalDateInterval periode = new LocalDateInterval(opdracht.getBeginDatum(), opdracht.getEindDatum());
            for (LocalDate beginDatum : kwartaalDatums) {
                if (periode.contains(beginDatum) && (currentMonth || !beginDatum.equals(rekenTijd.beginDatum))) {
                    regulManager.addRegul(beginDatum, opdracht, regulKode);
                }
            }
        }
    }

    protected void controleerRegulBasisRszNegatief(Opdracht opdracht, LoonElementManager manager, RegulManager regulManager) {
        Collection<LoonElement> elementen = manager.getOpdrachtsElementen(opdracht);
        Money basisRsz = RekenTools.getSomProperty(RekenBasisRszKey.BASIS_RSZ_KEY, elementen);
        if (basisRsz.signum() < 0) {
            AardKodeExtensie aardKodeExtensie = elementen.stream()
                    .filter(element -> element.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY).getAmount().signum() < 0)
                    .findFirst()
                    .map(LoonElement::getAardKodeExtensie)
                    .orElse(null);
            String message = "Nakijken " + (aardKodeExtensie != null ? aardKodeExtensie.getAard() : null) + '-' +
                    (aardKodeExtensie != null ? aardKodeExtensie.getCode() : null) + '-' + (aardKodeExtensie != null ? aardKodeExtensie.getExtensie() : null);
            regulManager.doRegulException(opdracht, Regulkode.NEGATIEVE_BAS_RSZ_ZIV, message);
        }
    }

